--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `order_number` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `customer_id` int DEFAULT NULL,
  `walkin_customer_name` varchar(150) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `walkin_customer_phone` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `type` enum('online','walkin') COLLATE utf8mb4_general_ci DEFAULT 'online',
  `order_type` enum('standard','blueprint') COLLATE utf8mb4_general_ci DEFAULT 'standard',
  `status` enum('pending','confirmed','contract_released','production','shipping','delivered','completed','cancelled') COLLATE utf8mb4_general_ci DEFAULT 'pending',
  `payment_method` enum('cash','gcash','bank_transfer','cod','cop') COLLATE utf8mb4_general_ci DEFAULT 'cash',
  `payment_status` enum('unpaid','partial','paid') COLLATE utf8mb4_general_ci DEFAULT 'unpaid',
  `subtotal` decimal(12,2) DEFAULT '0.00',
  `tax` decimal(10,2) DEFAULT '0.00',
  `discount` decimal(10,2) DEFAULT '0.00',
  `delivery_fee` decimal(10,2) DEFAULT '0.00',
  `total` decimal(12,2) DEFAULT '0.00',
  `cash_received` decimal(10,2) DEFAULT NULL,
  `change` decimal(10,2) NOT NULL DEFAULT '0.00',
  `down_payment` decimal(12,2) DEFAULT '0.00',
  `payment_proof` text COLLATE utf8mb4_general_ci,
  `delivery_address` text COLLATE utf8mb4_general_ci,
  `requested_delivery_date` datetime DEFAULT NULL,
  `delivery_request_notes` text COLLATE utf8mb4_general_ci,
  `notes` text COLLATE utf8mb4_general_ci,
  `blueprint_id` int DEFAULT NULL,
  `custom_request_id` int DEFAULT NULL,
  `cancellation_reason` text COLLATE utf8mb4_general_ci,
  `cancelled_at` datetime DEFAULT NULL,
  `refund_amount` decimal(12,2) DEFAULT '0.00',
  `refund_status` enum('none','pending','processed') COLLATE utf8mb4_general_ci DEFAULT 'none',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_number` (`order_number`),
  KEY `customer_id` (`customer_id`),
  KEY `blueprint_id` (`blueprint_id`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `users` (`id`),
  CONSTRAINT `orders_ibfk_2` FOREIGN KEY (`blueprint_id`) REFERENCES `blueprints` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=124 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

