  `id` int NOT NULL AUTO_INCREMENT,
  `barcode` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `name` varchar(200) COLLATE utf8mb4_general_ci NOT NULL,
  `description` text COLLATE utf8mb4_general_ci,
  `category_id` int DEFAULT NULL,
  `type` enum('standard','blueprint') COLLATE utf8mb4_general_ci DEFAULT 'standard',
  `image_url` text COLLATE utf8mb4_general_ci,
  `is_featured` tinyint(1) DEFAULT '0',
  `online_price` decimal(10,2) DEFAULT '0.00',
  `walkin_price` decimal(10,2) DEFAULT '0.00',
  `production_cost` decimal(10,2) DEFAULT '0.00',
  `profit_margin` decimal(10,2) GENERATED ALWAYS AS ((`walkin_price` - `production_cost`)) STORED,
  `stock` int DEFAULT '0',
  `reorder_point` int DEFAULT '0',
  `stock_status` enum('in_stock','low_stock','out_of_stock') COLLATE utf8mb4_general_ci DEFAULT 'in_stock',
  `is_published` tinyint(1) DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `barcode` (`barcode`),
  KEY `category_id` (`category_id`),
  CONSTRAINT `products_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
